	var mustEdges, nonMustEdges [][]int64
	for _, edge := range edges {
		if edge[3] == 1 {
			mustEdges = append(mustEdges, edge)
		} else {
			nonMustEdges = append(nonMustEdges, edge)
		}
	}

	// First, process must edges to check connectivity and cycles
	uf := NewUnionFind(n)
	components := n
	for _, edge := range mustEdges {
		u, v := edge[0], edge[1]
		if uf.Union(u, v) {
			components--
		}
	}

	// If must edges form a cycle, return -1
	if int64(len(mustEdges)) > n-1 {
		return -1
	}

	// If the must edges are not enough to connect the graph, we need to add non-must edges
	// Sort non-must edges in descending order of strength (original)
	sort.Slice(nonMustEdges, func(i, j int) bool {
		return nonMustEdges[i][2] > nonMustEdges[j][2]
	})

