	for _, edge := range mustEdges {
		selectedEdges = append(selectedEdges, edge)
	}

	// Add non-must edges to connect the graph
	for _, edge := range nonMustEdges {
		if components == 1 {
			break
		}
		u, v := edge[0], edge[1]
		if uf.Union(u, v) {
			selectedEdges = append(selectedEdges, edge)
			components--
		}
	}

	if components != 1 {
		return -1
	}

