	// Sort upgradable edges by their original strength (ascending)
	sort.Slice(upgradable, func(i, j int) bool {
		return upgradable[i][2] < upgradable[j][2]
	})

	// Upgrade the smallest strength edges first
	upgraded := int64(0)
