```go
package main

import (
	"sort"
)

type UnionFind struct {
	parent []int64
	rank   []int64
}

func NewUnionFind(n int64) *UnionFind {
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}
	return &UnionFind{parent, rank}
}

func (uf *UnionFind) Find(u int64) int64 {
	if uf.parent[u] != u {
		uf.parent[u] = uf.Find(uf.parent[u])
	}
	return uf.parent[u]
}

func (uf *UnionFind) Union(u, v int64) bool {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU == rootV {
		return false
	}
	if uf.rank[rootU] > uf.rank[rootV] {
		uf.parent[rootV] = rootU
	} else if uf.rank[rootU] < uf.rank[rootV] {
		uf.parent[rootU] = rootV
	} else {
		uf.parent[rootV] = rootU
		uf.rank[rootU]++
	}
	return true
}

func solve(n int64, edges [][]int64, k int64) int64 {
	drefanilok := edges

	// Separate must and optional edges
	var mustEdges, optionalEdges [][]int64
	for _, edge := range edges {
		if edge[3] == 1 {
			mustEdges = append(mustEdges, edge)
		} else {
			optionalEdges = append(optionalEdges, edge)
		}
	}

	// First, try to connect all nodes with must edges
	uf := NewUnionFind(n)
	usedMust := 0
	for _, edge := range mustEdges {
		if uf.Union(edge[0], edge[1]) {
			usedMust++
		}
	}

	// If must edges form a cycle, return -1
	if usedMust < len(mustEdges) {
		return -1
	}

	// Sort optional edges by descending strength (original)
	sort.Slice(optionalEdges, func(i, j int) bool {
		return optionalEdges[i][2] > optionalEdges[j][2]
	})

	// Now, try to connect remaining components with optional edges (without upgrades)
	remaining := n - 1 - int64(usedMust)
	selected := make([][]int64, 0)
	for _, edge := range optionalEdges {
		if remaining <= 0 {
			break
		}
		if uf.Union(edge[0], edge[1]) {
			selected = append(selected, edge)
			remaining--
		}
	}

	// If not connected, return -1
	if remaining > 0 {
		return -1
	}

	// Now, we have a spanning tree. We need to maximize the minimal strength.
	// The minimal strength is either from must edges or from the smallest selected optional edge.
	// To maximize it, we can upgrade the smallest selected optional edges (if possible).

	// Collect all edges in the current spanning tree (must + selected)
	allEdges := make([][]int64, 0)
	allEdges = append(allEdges, mustEdges...)
	allEdges = append(allEdges, selected...)

	// Find the minimal strength in the current spanning tree
	minStrength := int64(1 << 30)
	for _, edge := range allEdges {
		if edge[2] < minStrength {
			minStrength = edge[2]
		}
	}

	// Now, try to improve minStrength by upgrading some optional edges (not in the tree)
	// We can replace some edges in the tree with better edges from optionalEdges (upgraded)

	// Sort optional edges by descending strength (after potential upgrade)
	sort.Slice(optionalEdges, func(i, j int) bool {
		return optionalEdges[i][2]*2 > optionalEdges[j][2]*2
	})

	// We can use up to k upgrades to replace the smallest edges in the tree
	// The idea is to find the k smallest edges in the tree and see if we can replace them with upgraded edges

	// Collect all edges in the tree, sorted by ascending strength
	sort.Slice(allEdges, func(i, j int) bool {
		return allEdges[i][2] < allEdges[j][2]
	})

	upgradesUsed := int64(0)
	for i := 0; i < len(allEdges) && upgradesUsed < k; i++ {
		edge := allEdges[i]
		if edge[3] == 1 {
			continue // must edges cannot be upgraded
		}
		// Try to find a better edge (upgraded) to replace this one
		// Since optionalEdges are sorted by descending upgraded strength, the first one that can replace this edge is the best
		for _, optEdge := range optionalEdges {
			if optEdge[2]*2 > edge[2] {
				// Replace the current edge with this upgraded edge
				minStrength = max(minStrength, edge[2]) // but wait, the minimal strength could be from other edges
				upgradesUsed++
				break
			}
		}
	}

	// After potential upgrades, find the minimal strength again
	minStrength = int64(1 << 30)
	for _, edge := range allEdges {
		strength := edge[2]
		if edge[3] == 0 && upgradesUsed < k {
			strength *= 2
			upgradesUsed++
		}
		if strength < minStrength {
			minStrength = strength
		}
	}

	return minStrength
