			return -1
		}
	}

	// If selectedMust + remaining edges (n-1 - selectedMust) > total edges, return -1
	// But we have to ensure that we can select enough edges to form a spanning tree
	// The remaining edges needed is (n-1 - selectedMust)
	remainingNeeded := (n - 1) - int64(selectedMust)
	if remainingNeeded < 0 {
		return -1
	}

	// Now, process non-must edges with possible upgrades
	// We want to maximize the minimal strength, so we should prioritize edges with higher strength
	// Also, we can upgrade some edges to double their strength
	// Strategy: sort non-must edges by their strength (descending), and try to use as many as possible with upgrades

	// Make a list of possible strengths (original and upgraded)
	type edgeInfo struct {
		u, v   int64
		s      int64
		upgraded bool
	}
	var edgeInfos []edgeInfo
	for _, edge := range nonMustEdges {
		u, v, s := edge[0], edge[1], edge[2]
		edgeInfos = append(edgeInfos, edgeInfo{u, v, s, false})
		edgeInfos = append(edgeInfos, edgeInfo{u, v, s * 2, true})
	}

