	// We have to use up to k upgrades
	// We need to select remainingNeeded edges, and can use up to k upgraded edges
	// So, we should pick the highest strength edges, prioritizing upgraded ones if they give higher strength

	// Reset UnionFind
	uf = NewUnionFind(n)
	// First, add must edges
	for _, edge := range mustEdges {
		u, v := edge[0], edge[1]
		uf.Union(u, v)
	}

	selectedNonMust := int64(0)
	usedUpgrades := int64(0)
	minStrength := int64(1 << 62)

