	// So, we can process edgeInfos in order, and pick the edge if it connects two components
	// If it's an upgraded edge, we increment usedUpgrades, as long as usedUpgrades <= k

	for _, ei := range edgeInfos {
		if selectedNonMust >= remainingNeeded {
			break
		}
		if uf.Union(ei.u, ei.v) {
			selectedNonMust++
			if ei.upgraded {
				usedUpgrades++
			}
			if ei.s < minStrength {
				minStrength = ei.s
			}
		}
	}

	if selectedNonMust < remainingNeeded {
		return -1
	}

	if usedUpgrades > k {
		// Need to adjust, since we used more upgrades than allowed
		// So, we need to find a way to replace some upgraded edges with non-upgraded ones
		// This is complex, so we might need to re-process with a binary search approach
		// For simplicity, we'll implement a binary search approach instead

		// Binary search the minimal strength
		left := int64(1)
		right := int64(2e5)
		best := int64(-1)

