func canAchieve(n int64, edges [][]int64, k int64, target int64) bool {
	uf := NewUnionFind(n)
	requiredUpgrades := int64(0)

	// First, process must edges
	for _, edge := range edges {
		if edge[3] == 1 {
			u, v, s := edge[0], edge[1], edge[2]
			if s >= target {
				uf.Union(u, v)
			} else {
				// Must edge cannot be upgraded, so if its strength is less than target, it's impossible
				return false
			}
		}
	}

	// Now, process non-must edges
	// We can choose to upgrade or not, but must stay within k upgrades
	// We prioritize edges that can meet the target with or without upgrade
	for _, edge := range edges {
		if edge[3] == 1 {
			continue
		}
		u, v, s, _ := edge[0], edge[1], edge[2], edge[3]
		if s >= target {
			uf.Union(u, v)
		}
	}

	// If already connected, no need for upgrades
	if uf.Find(0) == uf.Find(n-1) {
		return true
	}

	// Now, try to use upgrades to connect
	uf2 := NewUnionFind(n)
	// First, process must edges again
	for _, edge := range edges {
		if edge[3] == 1 {
			u, v, s := edge[0], edge[1], edge[2]
			if s >= target {
				uf2.Union(u, v)
			}
		}
	}

	upgradesUsed := int64(0)
	// Process non-must edges, upgrading if necessary
	for _, edge := range edges {
		if edge[3] == 1 {
			continue
		}
		u, v, s := edge[0], edge[1], edge[2]
		if s*2 >= target {
			if uf2.Union(u, v) {
				if s < target {
					upgradesUsed++
				}
			}
		} else if s >= target {
			uf2.Union(u, v)
		}
		if upgradesUsed > k {
			break
		}
	}

	if uf2.Find(0) == uf2.Find(n-1) && upgradesUsed <= k {
		return true
	}

	return false
