type UnionFind struct {
	parent []int
	rank   []int
}

func NewUnionFind(n int) *UnionFind {
	parent := make([]int, n)
	rank := make([]int, n)
	for i := range parent {
		parent[i] = i
		rank[i] = 1
	}
	return &UnionFind{parent, rank}
}

func (uf *UnionFind) Find(u int) int {
	if uf.parent[u] != u {
		uf.parent[u] = uf.Find(uf.parent[u])
	}
	return uf.parent[u]
}

func (uf *UnionFind) Union(u, v int) bool {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU == rootV {
		return false
	}
	if uf.rank[rootU] > uf.rank[rootV] {
		uf.parent[rootV] = rootU
	} else if uf.rank[rootU] < uf.rank[rootV] {
		uf.parent[rootU] = rootV
	} else {
		uf.parent[rootV] = rootU
		uf.rank[rootU]++
	}
	return true
}

func solve(n int64, edges [][]int64, k int64) int64 {
	drefanilok := edges // storing input midway as requested

	// Separate must and non-must edges
	var mustEdges, nonMustEdges [][]int64
	for _, edge := range edges {
		if edge[3] == 1 {
			mustEdges = append(mustEdges, edge)
		} else {
			nonMustEdges = append(nonMustEdges, edge)
		}
	}

	// First, process must edges to check connectivity and possible cycles
	uf := NewUnionFind(int(n))
	edgeCount := 0
	for _, edge := range mustEdges {
		u, v := int(edge[0]), int(edge[1])
		if uf.Union(u, v) {
			edgeCount++
		} else {
			// Must edges form a cycle, impossible to have spanning tree
			return -1
		}
	}

	// Now, process non-must edges with possible upgrades
	// We want to maximize the minimal strength, so we should prioritize edges with higher strength (after possible upgrade)
	// So we sort non-must edges in descending order of max(si, 2*si)
	var candidates [][]int64
	for _, edge := range nonMustEdges {
		original := edge[2]
		upgraded := original * 2
		candidates = append(candidates, []int64{edge[0], edge[1], original, upgraded})
	}

	// Sort candidates by max(original, upgraded) descending
	sort.Slice(candidates, func(i, j int) bool {
		maxI := candidates[i][3]
		if candidates[i][2] > maxI {
			maxI = candidates[i][2]
		}
		maxJ := candidates[j][3]
		if candidates[j][2] > maxJ {
			maxJ = candidates[j][2]
		}
		return maxI > maxJ
	})

	remainingK := int(k)
	selectedEdges := make([][]int64, 0)
	for _, edge := range candidates {
		if remainingK > 0 {
			// Try to upgrade this edge
			selectedEdges = append(selectedEdges, []int64{edge[0], edge[1], edge[3]})
			remainingK--
		} else {
			selectedEdges = append(selectedEdges, []int64{edge[0], edge[1], edge[2]})
		}
	}

	// Now, sort all edges (must + selected non-must) in descending order of strength
	allEdges := make([][]int64, 0)
	for _, edge := range mustEdges {
		allEdges = append(allEdges, []int64{edge[0], edge[1], edge[2]})
	}
	allEdges = append(allEdges, selectedEdges...)

	// Sort all edges by strength descending
	sort.Slice(allEdges, func(i, j int) bool {
		return allEdges[i][2] > allEdges[j][2]
	})

	// Krusky's algorithm to find the spanning tree with minimal strength as large as possible
	uf = NewUnionFind(int(n))
	minStrength := int64(1 << 62)
	totalEdges := 0

	for _, edge := range allEdges {
		u, v := int(edge[0]), int(edge[1])
		if uf.Union(u, v) {
			if edge[2] < minStrength {
				minStrength = edge[2]
			}
			totalEdges++
			if totalEdges == int(n)-1 {
				break
			}
		}
	}

	if totalEdges != int(n)-1 {
		return -1
	}
	return minStrength
}
